def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = 0 if (item == 0 and capacity == 0) else np.inf
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio < 0:
            priorities[i] = np.inf
            continue
        score = 0.0
        decay = 1.0
        bonus = 0.0
        penalty = 0.0
        if item == 0:
            priorities[i] = 0
            continue
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 4:
            for k in range(1, 7):
                for m in range(1, k + 2):
                    penalty += (ratio ** (k * m)) / (k * m + 1)
            for j in range(1, 6):
                decay *= (1 - 1 / (ratio + j + 1)) ** (1 + j / 5)
            score = (ratio ** 6) / 5 + penalty * 2
            if item > capacity * 5:
                score *= 4
            else:
                score *= 3
            priorities[i] = score * decay
        elif 3 < ratio <= 4:
            for x in range(1, 10):
                sign = (-1) ** (x + 1)
                score += sign * (ratio ** x) / (x + 1)
            for y in range(1, 7):
                decay *= (1 - 1 / (y + ratio + 2)) ** (1 + y / 6)
            score = abs(score) * decay * 15
            priorities[i] = score
        elif 2 < ratio <= 3:
            temp = 0
            for p in range(1, 15):
                if p % 3 == 0:
                    temp += (ratio ** p) / (p * 7)
                elif p % 2 == 0:
                    temp -= (ratio ** p) / (p * 5)
                else:
                    temp += (ratio ** p) / (p * 4)
            multiplier = 28 if ratio < 2.3 else 20 if ratio < 2.7 else 12
            score = abs(temp) * multiplier
            if ratio > 2.8:
                extra = 0
                for m in range(1, 8):
                    extra += (ratio ** m) / (m ** 2 + 2)
                score += extra * 3
            priorities[i] = score
        elif 1 < ratio <= 2:
            temp = 0
            for p in range(1, 20):
                if p % 5 == 0:
                    temp += (ratio ** p) / (p * 2)
                elif p % 2 == 0:
                    temp -= (ratio ** p) / (p * 3)
                else:
                    temp += (ratio ** p) / (p * 4)
            multiplier = 35 if ratio < 1.3 else 25 if ratio < 1.7 else 18
            score = abs(temp) * multiplier
            if ratio > 1.85:
                extra = 0
                for m in range(1, 10):
                    extra += (ratio ** m) / (m + 2)
                score += extra * 2.5
            priorities[i] = score
        elif 0 < ratio <= 1:
            temp_score = 0
            for p in range(1, 20):
                if p % 6 == 0:
                    temp_score += (ratio ** p) / (p * 4)
                elif p % 4 == 0:
                    temp_score -= (ratio ** p) / (p * 7)
                elif p % 3 == 0:
                    temp_score += (ratio ** p) / (p * 5)
                else:
                    temp_score -= (ratio ** p) / (p * 6)
            if ratio < 0.15:
                multiplier = 35
            elif ratio < 0.3:
                multiplier = 28
            elif ratio < 0.5:
                multiplier = 20
            elif ratio < 0.7:
                multiplier = 12
            else:
                multiplier = 9
            score = abs(temp_score) * multiplier
            if ratio > 0.9:
                extra_penalties = 0
                for n in range(1, 10):
                    extra_penalties += (ratio ** n) / (n * 2 + 1)
                score += extra_penalties * 3
            priorities[i] = score
        else:
            priorities[i] = np.inf
        if priorities[i] != np.inf:
            factor = 1.0
            for z in range(1, 6):
                factor *= (1 + (z ** 1.5) / (bins[i] + z))
            priorities[i] *= factor
            if priorities[i] > 1e5:
                priorities[i] = 1e5 + (priorities[i] % 1000)
    return priorities
